def assess(record: dict) -> str:
    required = {'case_id', 'holdout', 'rubric_levels', 'tasks', 'slices'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = not (sum(record["slices"].values()) != record["tasks"] or record["holdout"] == 0)
    return "PASS" if ok else 'REBUILD_EVAL_DATASET'

